import { useState } from "react";

function CreatePostModal({ isOpen, onClose }) {
  const [content, setContent] = useState("");
  const [image, setImage] = useState(null);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center">

      <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl p-5">

        {/* Header */}
        <div className="flex items-center justify-between border-b pb-3">
          <h2 className="text-xl font-bold">Create Post</h2>

          <button
            onClick={onClose}
            className="w-9 h-9 rounded-full bg-gray-100 hover:bg-gray-200"
          >
            ✕
          </button>
        </div>

        {/* User */}
        <div className="flex items-center gap-3 mt-4">

          <div className="w-12 h-12 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold">
            A
          </div>

          <div>
            <h4 className="font-semibold">Akkas</h4>

            <select className="bg-gray-100 px-2 py-1 rounded-lg text-sm outline-none">
              <option>Public</option>
              <option>Private</option>
            </select>
          </div>
        </div>

        {/* Textarea */}
        <textarea
          value={content}
          onChange={(e) => setContent(e.target.value)}
          placeholder="What's on your mind?"
          className="w-full mt-5 min-h-[120px] resize-none outline-none text-lg"
        />

        {/* Preview */}
        {image && (
          <img
            src={URL.createObjectURL(image)}
            alt="preview"
            className="w-full rounded-xl mt-3"
          />
        )}

        {/* Upload */}
        <label className="border-2 border-dashed border-gray-300 rounded-xl p-6 flex flex-col items-center justify-center cursor-pointer hover:bg-gray-50 transition mt-4">

          <span className="text-2xl">📷</span>

          <p className="text-gray-500 mt-2">
            Add Photos/Videos
          </p>

          <input
            type="file"
            hidden
            accept="image/*"
            onChange={(e) => setImage(e.target.files[0])}
          />
        </label>

        {/* Button */}
        <button className="w-full bg-blue-600 hover:bg-blue-700 transition text-white py-3 rounded-xl font-semibold mt-5">
          Post
        </button>

      </div>
    </div>
  );
}

export default CreatePostModal;
